import { GoogleGenAI, Type } from "@google/genai";

const SYSTEM_INSTRUCTION = `
You are the AI assistant for GABdev, a community platform for Gabonese developers and tech enthusiasts founded by Ivan Ndoumba Nguia.
Your mission is to:
1. Promote digital innovation in Gabon.
2. Answer coding questions with expertise.
3. Inform users about local tech ecosystem and community life.
4. Maintain a professional, encouraging, and visionary tone.
5. Speak primarily French (as it is the national language of Gabon) but assist in English if requested.

When asked for the WhatsApp community link, share this: https://chat.whatsapp.com/JWIFORvnz119IButUK04Rw
When asked for Ivan's LinkedIn profile or how to contact the founder on social media, share this: https://www.linkedin.com/in/ivan-ndoumba-nguia-a025053a4
`;

/**
 * Sends a message to the Gemini API using the Chat interface to maintain context.
 */
export const sendMessageToGemini = async (message: string, history: { role: 'user' | 'model', text: string }[]) => {
  // Always initialize GoogleGenAI with the direct process.env.API_KEY as per the guidelines.
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const chat = ai.chats.create({
      model: 'gemini-3-flash-preview',
      // Properly map history to the format expected by the Gemini API.
      history: history.map(msg => ({
        role: msg.role,
        parts: [{ text: msg.text }]
      })),
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
      },
    });

    // Use chat.sendMessage to continue the conversation thread.
    const response = await chat.sendMessage({ message: message });
    // Access the text property directly on the response object.
    return response.text;
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Désolé, j'ai rencontré une erreur lors du traitement de votre demande. Veuillez réessayer plus tard.";
  }
};

