const JoinHub: React.FC = () => {
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [members, setMembers] = useState<Member[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);
  const [nrStatus, setNrStatus] = useState<'IDLE' | 'CONNECTED' | 'ERROR'>('IDLE');

  useEffect(() => {
    const saved = localStorage.getItem('gabdev_members');
    if (saved) setMembers(JSON.parse(saved));
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name || !email) return;

    setIsSubmitting(true);

    const newMember: Member = {
      id: Math.random().toString(36).substr(2, 9),
      hacker_name: name,
      email: email,
      registered_at: new Date().toLocaleString('fr-FR')
    };

    const nrResult = await sendToNodeRed('/gabdev/join', newMember);
    setNrStatus(nrResult ? 'CONNECTED' : 'ERROR');

    setTimeout(() => {
      const updatedMembers = [newMember, ...members];
      setMembers(updatedMembers);
      localStorage.setItem('gabdev_members', JSON.stringify(updatedMembers));
      setName('');
      setEmail('');
      setIsSubmitting(false);
      setShowSuccess(true);
      setTimeout(() => setShowSuccess(false), 5000);
    }, 1200);
  };

