            <div className="space-y-6 p-8 rounded-[40px] bg-zinc-900/40 border border-white/5 inline-block w-full max-w-md">
              <h3 className="text-[11px] font-black tracking-[0.2em] text-zinc-600 uppercase mb-8 flex items-center gap-2">
                <span className="w-1.5 h-6 bg-[#22c55e] rounded-full" aria-hidden="true" />
                Contact Direct
              </h3>

              <div className="flex items-center gap-4">
                <div className="w-12 h-12 rounded-xl bg-blue-500/10 flex items-center justify-center flex-shrink-0" aria-hidden="true">
